export async function getBranches(organizationId: number) {
  const sql = getSql()
  const result = await sql`
    SELECT DISTINCT branch
    FROM test_executions
    WHERE organization_id = ${organizationId}
    ORDER BY branch ASC
  `
  return result.map((r) => r.branch) as string[]
}

export async function getSuites(organizationId: number) {
  const sql = getSql()
  const result = await sql`
    SELECT DISTINCT suite
    FROM test_executions
    WHERE suite IS NOT NULL
      AND organization_id = ${organizationId}
    ORDER BY suite ASC
  `
  return result.map((r) => r.suite) as string[]
}

solution.updated_db_function_branches:
export async function getBranches(
  organizationId: number,
  days: number = 30
): Promise<BranchStatistics[]> {
  const sql = getSql()

  const result = await sql`
    WITH branch_stats AS (
      SELECT
        branch,
        MAX(started_at) as last_run,
        COUNT(*) as execution_count,
        ROUND(
          AVG(CASE WHEN status = 'success' THEN 100 ELSE 0 END)::numeric,
          1
        ) as pass_rate,
        (
          SELECT status FROM test_executions te2
          WHERE te2.branch = te.branch
            AND te2.organization_id = ${organizationId}
          ORDER BY started_at DESC
          LIMIT 1
        ) as last_status
      FROM test_executions te
      WHERE organization_id = ${organizationId}
        AND started_at > NOW() - INTERVAL '${days} days'
      GROUP BY branch
    )
    SELECT branch, last_run, execution_count, pass_rate, last_status
    FROM branch_stats
    ORDER BY last_run DESC NULLS LAST
  `

  return result as BranchStatistics[]
}

solution.updated_db_function_suites:
export async function getSuites( organizationId: number, days: number = 30 ): Promise<SuiteStatistics[]> { const sql = getSql()
const result = await sql` WITH suite_stats AS ( SELECT suite, MAX(started_at) as last_run, COUNT(*) as execution_count, ROUND( AVG(CASE WHEN status = 'success' THEN 100 ELSE 0 END)::numeric, 1 ) as pass_rate, ( SELECT status FROM test_executions te2 WHERE te2.suite = te.suite AND te2.organization_id = ${organizationId} ORDER BY started_at DESC LIMIT 1 ) as last_status FROM test_executions te WHERE suite IS NOT NULL AND organization_id = ${organizationId} AND started_at > NOW() - INTERVAL '${days} days' GROUP BY suite ) SELECT suite, last_run, execution_count, pass_rate, last_status FROM suite_stats ORDER BY last_run DESC NULLS LAST `
return result as SuiteStatistics[] }

solution.updated_tool_definition_branches:
{
  name: "list_branches",
  description: `Get list of branches with test run statistics.

Fields returned per branch:
- branch: string - Branch name
- last_run: ISO datetime - Most recent execution
- execution_count: number - Total runs in period
- pass_rate: number - Average success rate (0-100)
- last_status: "success" | "failure" | "running" - Most recent execution status`,
  inputSchema: {
    type: "object" as const,
    properties: {
      days: {
        type: "number",
        default: 30,
        description: "Only include branches with runs in the last N days (default: 30)",
      },
    },
  },
}

